tools.handler:
var token = getVar('slack_bot_token');
var limit = args.limit || 20;
var resp = httpGet('https://slack.com/api/conversations.list?limit=' + limit + '&types=public_channel,private_channel', {'Authorization': 'Bearer ' + token});
var body = resp.body;
if (!body.ok) return JSON.stringify({error: body.error});
var channels = (body.channels || []).map(function(c) {
  return {id: c.id, name: c.name, topic: (c.topic && c.topic.value) || '', member_count: c.num_members};
});
return JSON.stringify(channels, null, 2);

var token = getVar('slack_bot_token');
var limit = args.limit || 10;
var resp = httpGet('https://slack.com/api/conversations.history?channel=' + args.channel + '&limit=' + limit, {'Authorization': 'Bearer ' + token});
var body = resp.body;
if (!body.ok) return JSON.stringify({error: body.error});
var messages = (body.messages || []).map(function(m) {
  return {user: m.user || m.bot_id || 'unknown', text: m.text, ts: m.ts, type: m.type};
});
return JSON.stringify(messages, null, 2);

var token = getVar('slack_bot_token');
var resp = httpPost('https://slack.com/api/chat.postMessage', JSON.stringify({channel: args.channel, text: args.text}), {'Authorization': 'Bearer ' + token, 'Content-Type': 'application/json'});
var body = resp.body;
if (!body.ok) return JSON.stringify({error: body.error});
return JSON.stringify({ok: true, ts: body.ts, channel: body.channel}, null, 2);
